using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Fix 1: EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Keep the old name so existing documents and raw SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // Fix 2: EF Core 9 maps the key property directly to the JSON "id" field.
            // Previously a shadow property "__id" held a synthesized "Blog|{key}" value.
            // Restore that layout so existing documents are found by their original ids.
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();
            b.HasKey("__id");
            b.Property(e => e.Id).ToJsonProperty("Id");

            // Fix 3: HasIndex now throws for Cosmos entities — removed.
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "{Discriminator}|{Key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
            ?? entry.Metadata.ShortName();
        var id = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{id}";
    }

    public override bool GeneratesTemporaryValues => false;
}

